260	async function executePrompt(input: {
261	  provider: ProviderName;
262	  specPackRoot: string;
263	  model: string;
264	  reasoningEffort: string;
265	  prompt: string;
266	  resumeSessionId?: string;
267	  env?: Record<string, string | undefined>;
268	}): Promise<PromptExecutionSuccess | PromptExecutionFailure> {
269	  const adapter = createProviderAdapter(input.provider, {
270	    env: input.env,
271	  });
272	  const execution = await adapter.execute({
273	    prompt: input.prompt,
274	    cwd: input.specPackRoot,
275	    model: input.model,
276	    reasoningEffort: input.reasoningEffort,
277	    resumeSessionId: input.resumeSessionId,
278	    timeoutMs: 30_000,
279	    resultSchema: providerPayloadSchema,
280	  });
281	
282	  if (execution.exitCode !== 0) {
283	    return {
284	      outcome: "blocked" as const,
285	      errors: [
286	        executionFailureError({
287	          provider: input.provider,
288	          stderr: execution.stderr,
289	          errorCode: execution.errorCode,
290	        }),
291	      ],
292	    };
293	  }
294	
295	  if (execution.parseError || !execution.parsedResult) {
296	    return {
297	      outcome: "blocked" as const,
298	      errors: [
299	        blockedError(
300	          "PROVIDER_OUTPUT_INVALID",
301	          `Provider output was invalid for ${input.provider}.`,
302	          execution.parseError
303	        ),
304	      ],
305	    };
306	  }
307	
308	  const sessionId = execution.sessionId ?? input.resumeSessionId;
309	  if (!sessionId) {
310	    return {
311	      outcome: "blocked" as const,
312	      errors: [
313	        blockedError(
314	          "CONTINUATION_HANDLE_INVALID",
315	          `Provider ${input.provider} did not return a session id for a retained implementor workflow.`
316	        ),
317	      ],
318	    };
319	  }
320	
321	  return {
322	    outcome: execution.parsedResult.outcome,
323	    sessionId,
324	    payload: execution.parsedResult,
325	  };
326	}
