377	export async function validateContinuationHandle(input: {
378	  specPackRoot: string;
379	  storyId: string;
380	  provider: string;
381	  sessionId: string;
382	}): Promise<CliError | null> {
383	  const provider = providerIdSchema.safeParse(input.provider);
384	  if (!provider.success) {
385	    return blockedError(
386	      "CONTINUATION_HANDLE_INVALID",
387	      `Provider '${input.provider}' is not a valid continuation provider.`
388	    );
389	  }
390	
391	  const owner = await resolveContinuationOwner({
392	    specPackRoot: input.specPackRoot,
393	    provider: provider.data,
394	    sessionId: input.sessionId,
395	  });
396	  if (owner === input.storyId) {
397	    return null;
398	  }
399	
400	  if (owner) {
401	    return blockedError(
402	      "CONTINUATION_HANDLE_INVALID",
403	      `Continuation handle ${input.sessionId} belongs to '${owner}', not '${input.storyId}'.`
404	    );
405	  }
406	
407	  return blockedError(
408	    "CONTINUATION_HANDLE_INVALID",
409	    `Continuation handle ${input.sessionId} was not found for story '${input.storyId}'.`
410	  );
411	}
