413	export async function runStoryImplement(input: {
414	  specPackRoot: string;
415	  storyId: string;
416	  configPath?: string;
417	  env?: Record<string, string | undefined>;
418	}): Promise<StoryWorkflowResult> {
419	  const context = await prepareStoryContext(input);
420	  if ("errors" in context) {
421	    return {
422	      outcome: "blocked",
423	      errors: context.errors,
424	      warnings: [],
425	    };
426	  }
427	
428	  const prompt = await assemblePrompt({
429	    role: "story_implementor",
430	    storyId: context.story.id,
431	    storyTitle: context.story.title,
432	    storyPath: context.story.path,
433	    epicPath: context.paths.epicPath,
434	    techDesignPath: context.paths.techDesignPath,
435	    techDesignCompanionPaths: context.paths.techDesignCompanionPaths,
436	    testPlanPath: context.paths.testPlanPath,
437	    gateCommands: context.gateCommands,
438	    implementationPromptInsertPath: context.implementationPromptInsertPath,
439	  });
440	  const initial = await executePrompt({
441	    provider: context.provider,
442	    specPackRoot: context.specPackRoot,
443	    model: context.model,
444	    reasoningEffort: context.reasoningEffort,
445	    prompt: prompt.prompt,
446	    env: input.env,
447	  });
448	  if ("errors" in initial) {
449	    return {
450	      outcome: "blocked",
451	      errors: initial.errors,
452	      warnings: [],
453	    };
454	  }
455	
456	  let payload = initial.payload;
457	  let sessionId = initial.sessionId;
458	  let passesRun = 0;
459	
460	  if (payload.outcome !== "blocked" && payload.outcome !== "needs-human-ruling") {
461	    for (let pass = 1; pass <= context.selfReviewPasses; pass += 1) {
462	      const reviewPrompt = await assemblePrompt({
463	        role: "story_implementor",
464	        storyId: context.story.id,
465	        storyTitle: context.story.title,
466	        storyPath: context.story.path,
467	        epicPath: context.paths.epicPath,
468	        techDesignPath: context.paths.techDesignPath,
469	        techDesignCompanionPaths: context.paths.techDesignCompanionPaths,
470	        testPlanPath: context.paths.testPlanPath,
471	        gateCommands: context.gateCommands,
472	        implementationPromptInsertPath: context.implementationPromptInsertPath,
473	        selfReviewPass: pass,
474	      });
475	      const review = await executePrompt({
476	        provider: context.provider,
477	        specPackRoot: context.specPackRoot,
478	        model: context.model,
479	        reasoningEffort: context.reasoningEffort,
480	        prompt: reviewPrompt.prompt,

481	        resumeSessionId: sessionId,
482	        env: input.env,
483	      });
484	      if ("errors" in review) {
485	        return {
486	          outcome: "blocked",
487	          errors: review.errors,
488	          warnings: [],
489	        };
490	      }
491	
492	      payload = review.payload;
493	      sessionId = review.sessionId;
494	      passesRun = pass;
495	
496	      if (payload.outcome === "blocked" || payload.outcome === "needs-human-ruling") {
497	        break;
498	      }
499	    }
500	  }
501	
502	  const result = buildImplementorResult({
503	    provider: context.provider,
504	    model: context.model,
505	    sessionId,
506	    story: context.story,
507	    payload,
508	    passesRun,
509	  });
510	
511	  return {
512	    outcome: payload.outcome,
513	    result,
514	    errors: [],
515	    warnings: [],
516	  };
517	}
