187	function statusForOutcome(outcome: string): CliStatus {
188	  switch (outcome) {
189	    case "ready":
190	    case "ready-for-verification":
191	    case "needs-followup-fix":
192	    case "pass":
193	    case "revise":
194	    case "cleaned":
195	    case "needs-more-cleanup":
196	    case "ready-for-closeout":
197	    case "needs-fixes":
198	    case "needs-more-routing":
199	    case "needs-more-verification":
200	      return "ok";
201	    case "needs-user-decision":
202	    case "needs-human-ruling":
203	      return "needs-user-decision";
204	    case "blocked":
205	      return "blocked";
206	    default:
207	      return "error";
208	  }
209	}
