211	export function exitCodeForStatus(status: CliStatus): number {
212	  switch (status) {
213	    case "ok":
214	      return 0;
215	    case "needs-user-decision":
216	      return 2;
217	    case "blocked":
218	      return 3;
219	    case "error":
220	    default:
221	      return 1;
222	  }
223	}
