265	export function createResultEnvelope<T>(input: {
266	  command: string;
267	  outcome: string;
268	  result?: T;
269	  errors?: CliError[];
270	  warnings?: string[];
271	  artifacts?: CliArtifactRef[];
272	  startedAt: string;
273	  finishedAt: string;
274	}) {
275	  return {
276	    command: input.command,
277	    version: 1 as const,
278	    status: statusForOutcome(input.outcome),
279	    outcome: input.outcome,
280	    result: input.result,
281	    errors: input.errors ?? [],
282	    warnings: input.warnings ?? [],
283	    artifacts: input.artifacts ?? [],
284	    startedAt: input.startedAt,
285	    finishedAt: input.finishedAt,
286	  };
287	}

