259	  );
260	  await writeTextFile(cursorPath, "0\n");
261	  await writeTextFile(
262	    scriptPath,
263	    [
264	      "#!/usr/bin/env bun",
265	      "import { appendFileSync, existsSync, readFileSync, writeFileSync } from \"node:fs\";",
266	      "import { basename } from \"node:path\";",
267	      "",
268	      "const provider = basename(process.argv[1]);",
269	      "const prefix = provider.toUpperCase().replace(/-/g, \"_\");",
270	      "const envKey = (name) => `${prefix}_${name}`;",
271	      "const args = process.argv.slice(2);",
272	      "const logPath = process.env[envKey(\"LOG_PATH\")];",
273	      "",
274	      "if (logPath) {",
275	      "  appendFileSync(logPath, `${JSON.stringify({ provider, cwd: process.cwd(), args })}\\n`);",
276	      "}",
277	      "",
278	      "if (args.length === 1 && args[0] === \"--version\") {",
279	      "  process.stdout.write(process.env[envKey(\"VERSION\")] ?? `${provider} 1.0.0`);",
280	      "  process.exit(Number(process.env[envKey(\"VERSION_EXIT_CODE\")] ?? 0));",
281	      "}",
282	      "",
283	      "if (args[0] === \"auth\" && args[1] === \"status\") {",
284	      "  const authStatus = process.env[envKey(\"AUTH_STATUS\")] ?? \"authenticated\";",
285	      "  if (authStatus === \"authenticated\") {",
286	      "    process.stdout.write(process.env[envKey(\"AUTH_STDOUT\")] ?? \"authenticated\");",
287	      "    process.exit(0);",
288	      "  }",
289	      "  process.stderr.write(process.env[envKey(\"AUTH_STDERR\")] ?? \"missing\");",
290	      "  process.exit(1);",
291	      "}",
292	      "",
293	      "const responsesPath = process.env[envKey(\"RESPONSES_PATH\")];",
294	      "const cursorPath = process.env[envKey(\"CURSOR_PATH\")];",
295	      "if (!responsesPath || !cursorPath) {",
296	      "  process.stderr.write(\"Missing fake provider response configuration\");",
297	      "  process.exit(1);",
298	      "}",
299	      "",
300	      "const responses = JSON.parse(readFileSync(responsesPath, \"utf8\"));",
301	      "const rawCursor = existsSync(cursorPath) ? readFileSync(cursorPath, \"utf8\").trim() : \"0\";",
302	      "const cursor = Number(rawCursor || \"0\");",
303	      "const response = responses[cursor] ?? responses[responses.length - 1] ?? {",
304	      "  stderr: \"No fake provider response configured\",",
305	      "  exitCode: 1,",
306	      "};",
307	      "writeFileSync(cursorPath, `${cursor + 1}`);",
308	      "if (response.stderr) {",
309	      "  process.stderr.write(response.stderr);",
310	      "}",
311	      "if (response.stdout) {",
312	      "  process.stdout.write(response.stdout);",
313	      "}",
314	      "process.exit(Number(response.exitCode ?? 0));",
315	      "",
316	    ].join("\n")
317	  );
318	  await chmod(scriptPath, 0o755);
319	
320	  return {
321	    logPath,
322	    env: {
323	      [`${prefix}_LOG_PATH`]: logPath,
324	      [`${prefix}_RESPONSES_PATH`]: responsesPath,
325	      [`${prefix}_CURSOR_PATH`]: cursorPath,
326	      [`${prefix}_VERSION`]: params.version ?? `${params.provider} 1.0.0`,
